if (! function_exists('web_research')) {
    function web_research($url, $summarize = null, $max_summary_sentences = null, $max_text_length = null, $timeout = null)
    {
        if (!is_string($url) || $url === '') {
            return ['error' => 'URL is required.', 'title' => '', 'text' => '', 'summary' => null, 'links' => []];
        }

        $summarize = isset($summarize) ? (bool)$summarize : true;
        $max_summary_sentences = isset($max_summary_sentences) ? max(1, min(20, (int)$max_summary_sentences)) : 5;
        $max_text_length = isset($max_text_length) ? max(1024, min(100000, (int)$max_text_length)) : 30000;
        $timeout = isset($timeout) ? max(5, min(40, (int)$timeout)) : 20;

        // --- Step 1: Fetch the URL ---
        $ctx_opts = [
            'http' => [
                'method' => 'GET',
                'header' => "User-Agent: self-bootstrapping-agent/1.0\r\nAccept: text/html,application/xhtml+xml",
                'timeout' => $timeout,
                'max_redirects' => 5,
                'follow_location' => 1,
                'ignore_errors' => true,
            ],
            'ssl' => [
                'verify_peer' => true,
                'verify_peer_name' => true,
            ],
        ];
        $context = stream_context_create($ctx_opts);

        $error_msg = null;
        set_error_handler(function ($sev, $msg) use (&$error_msg) { $error_msg = $msg; return true; });
        $html = @file_get_contents($url, false, $context);
        $http_headers = $http_response_header ?? [];
        restore_error_handler();

        if ($html === false) {
            $reason = $error_msg ?? 'Failed to fetch URL.';
            if (preg_match('/Failed to open stream: (.+)$/', $reason, $m)) $reason = trim($m[1]);
            return ['error' => $reason, 'title' => '', 'text' => '', 'summary' => null, 'links' => [], 'http_status' => 0];
        }

        $status_code = 0;
        foreach ($http_headers as $i => $line) {
            if ($i === 0 && preg_match('#HTTP/\d+\.\d+ (\d+)#', $line, $m)) {
                $status_code = (int)$m[1];
                break;
            }
        }

        $content_type = '';
        foreach ($http_headers as $line) {
            if (stripos($line, 'content-type:') === 0 && preg_match('/:\s*(.+)/i', $line, $m)) {
                $content_type = trim($m[1]);
                break;
            }
        }

        // Only parse HTML
        if (!str_contains($content_type, 'html') && !str_contains($content_type, 'text')) {
            return [
                'error' => null,
                'title' => '',
                'text' => '[Non-HTML content: ' . $content_type . ' — ' . strlen($html) . ' bytes]',
                'summary' => null,
                'links' => [],
                'http_status' => $status_code,
                'content_type' => $content_type,
                'note' => 'Content is not HTML; raw body size: ' . strlen($html) . ' bytes',
            ];
        }

        // --- Step 2: Parse HTML to text ---
        libxml_use_internal_errors(true);
        $dom = new DOMDocument();
        $dom->loadHTML('<?xml encoding="UTF-8">' . $html);
        libxml_use_internal_errors(false);

        $xpath = new DOMXPath($dom);

        $title_node = $xpath->query('//title')->item(0);
        $title = $title_node ? trim($title_node->textContent) : '';

        // Remove scripts, styles, nav
        foreach (['//script', '//style', '//noscript', '//iframe', '//nav', '//header', '//footer', '//aside'] as $expr) {
            foreach ($xpath->query($expr) as $node) {
                $node->parentNode->removeChild($node);
            }
        }

        // Extract links
        $links = [];
        foreach ($xpath->query('//a[@href]') as $anchor) {
            $href = $anchor->getAttribute('href');
            if ($href === '' || $href === '#' || str_starts_with($href, 'javascript:')) continue;
            $text = trim($anchor->textContent);
            if ($text !== '') {
                $links[] = ['href' => $href, 'text' => mb_strlen($text) > 150 ? mb_substr($text, 0, 150) . '...' : $text];
                if (count($links) >= 50) break;
            }
        }

        $body_nodes = $xpath->query('//body');
        $raw_text = $body_nodes->length > 0 ? $body_nodes->item(0)->textContent : $dom->textContent;
        $raw_text = str_replace(["\xc2\xa0", "\xa0"], ' ', $raw_text);
        $raw_text = preg_replace('/[ \t]+/', ' ', $raw_text);
        $raw_text = preg_replace('/\n{3,}/', "\n\n", $raw_text);
        $raw_text = trim($raw_text);

        $text_truncated = false;
        if (mb_strlen($raw_text) > $max_text_length) {
            $raw_text = mb_substr($raw_text, 0, $max_text_length) . "\n\n[... truncated ...]";
            $text_truncated = true;
        }

        // --- Step 3: Summarize (extractive, using text_summarizer logic) ---
        $summary = null;
        $summary_method = null;
        if ($summarize && mb_strlen($raw_text) > 100) {
            // Split into sentences
            $sentences = preg_split('/(?<=[.!?])\s+/', $raw_text, 50, PREG_SPLIT_NO_EMPTY);
            $clean_sentences = [];
            foreach ($sentences as $s) {
                $s = trim($s);
                if (mb_strlen($s) > 20) $clean_sentences[] = $s;
            }

            if (count($clean_sentences) > 0) {
                // Score sentences: prefer earlier ones and those with frequent content words
                $total = count($clean_sentences);
                $word_freq = [];
                $stop_words = ['the','a','an','and','or','but','in','on','at','to','for','of','by','with','from','is','are','was','were','be','been','being','have','has','had','do','does','did','will','would','could','should','may','might','shall','can','need','dare','ought','used','this','that','these','those','it','its','it\'s','they','them','their','we','us','our','you','your','he','him','his','she','her','i','me','my','not','no','nor','so','as','if','then','than','also','very','just','about','up','out','over','after','before','between','through','during','because','while','since','until','all','each','every','both','few','more','most','some','any','such','only','own','same','too','very','can','will','just','should','now'];
                
                foreach ($clean_sentences as $s) {
                    $words = preg_split('/\W+/', strtolower($s));
                    foreach ($words as $w) {
                        $w = trim($w);
                        if (mb_strlen($w) > 2 && !in_array($w, $stop_words, true)) {
                            $word_freq[$w] = ($word_freq[$w] ?? 0) + 1;
                        }
                    }
                }

                $scored = [];
                foreach ($clean_sentences as $i => $s) {
                    $pos_score = 1.0 - ($i / $total) * 0.5; // earlier sentences score higher
                    $words = preg_split('/\W+/', strtolower($s));
                    $freq_score = 0;
                    $count_words = 0;
                    foreach ($words as $w) {
                        $w = trim($w);
                        if (isset($word_freq[$w]) && mb_strlen($w) > 2) {
                            $freq_score += $word_freq[$w];
                            $count_words++;
                        }
                    }
                    $freq_score = $count_words > 0 ? $freq_score / $count_words : 0;
                    $scored[] = ['idx' => $i, 'score' => $pos_score + $freq_score * 0.3];
                }

                arsort($scored);
                $top_idx = [];
                $n = min($max_summary_sentences, count($scored));
                $i = 0;
                foreach ($scored as $s) {
                    if ($i >= $n) break;
                    $top_idx[] = $s['idx'];
                    $i++;
                }
                sort($top_idx);

                $summary_sentences = [];
                foreach ($top_idx as $idx) {
                    $summary_sentences[] = $clean_sentences[$idx];
                }
                $summary = implode(' ', $summary_sentences);
                $summary_method = 'extractive_frequency';
            }
        }

        $fetch_size = strlen($html);

        return [
            'error' => null,
            'url' => $url,
            'http_status' => $status_code,
            'title' => $title,
            'text' => $raw_text,
            'text_length' => mb_strlen($raw_text),
            'text_truncated' => $text_truncated,
            'fetch_size_bytes' => $fetch_size,
            'summary' => $summary,
            'summary_sentences' => $summary ? count(explode('. ', $summary)) : 0,
            'summary_method' => $summary_method,
            'links' => $links,
            'link_count' => count($links),
        ];
    }
}
